  dotenv.config({ path: path.resolve(__dirname, '.env') });
}

const requiredEnvVars = [
  'DB_HOST',
  'DB_PORT',
  'DB_USER',
  'DB_PASSWORD',
  'DB_NAME',
  'JWT_SECRET',
  'AWS_ACCESS_KEY_ID',
